Here is the cycle-safe deep clone implementation:

```typescript
function baseClone<T>(value: T, visited: WeakMap<object, unknown>): T {
  if (value === null || (typeof value !== 'object' && typeof value !== 'function')) return value;
  if (typeof value === 'function') return value;
  const obj = value as object;
  if (visited.has(obj)) return visited.get(obj) as T;
  const tag = Object.prototype.toString.call(obj);
  if (tag === '[object Date]') { const c = new Date((obj as Date).getTime()); visited.set(obj, c); return c as unknown as T; }
  if (tag === '[object RegExp]') { const r = obj as RegExp; const c = new RegExp(r.source, r.flags); c.lastIndex = 0; visited.set(obj, c); return c as unknown as T; }
  if (tag === '[object Map]') { const c = new Map(); visited.set(obj, c); for (const [k,v] of obj as Map<unknown,unknown>) c.set(baseClone(k,visited), baseClone(v,visited)); return c as unknown as T; }
  if (tag === '[object Set]') { const c = new Set(); visited.set(obj, c); for (const v of obj as Set<unknown>) c.add(baseClone(v,visited)); return c as unknown as T; }
  if (Array.isArray(obj)) { const c: unknown[] = []; visited.set(obj, c); for (let i=0;i<obj.length;i++) c[i]=baseClone(obj[i],visited); return c as unknown as T; }
  const c = Object.create(Object.getPrototypeOf(obj));
  visited.set(obj, c);
  for (const k of Object.getOwnPropertyNames(obj)) c[k] = baseClone((obj as Record<string,unknown>)[k], visited);
  for (const s of Object.getOwnPropertySymbols(obj)) c[s] = baseClone((obj as Record<symbol,unknown>)[s], visited);
  return c;
}

export default function deepClone<T>(value: T): T {
  return baseClone(value, new WeakMap());
}
